import json

baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def normalize(data):
    """Build dict: (project_basename, framework, package_id) -> (requested, resolved)"""
    result = {}
    for proj in data['projects']:
        pname = proj['path'].rsplit('/', 1)[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, fw['framework'], pkg['id'])
                result[key] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return result

b = normalize(baseline)
a = normalize(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    proj, fw, pkg = k
    bv = b.get(k)
    av = a.get(k)
    if bv and av:
        if bv[1] != av[1]:
            changes.append((proj, fw, pkg, bv[1], av[1], "Aligned to highest version"))
        elif bv[0] != av[0]:
            changes.append((proj, fw, pkg, bv[1], av[1], f"Requested changed ({bv[0]} → {av[0]})"))
        else:
            unchanged.append((proj, fw, pkg, av[1]))
    elif bv and not av:
        changes.append((proj, fw, pkg, bv[1], "—", "Removed"))
    elif av and not bv:
        changes.append((proj, fw, pkg, "—", av[1], "Added"))

print("=== CHANGES ===")
if changes:
    print(f"{'Project':<15} {'Framework':<8} {'Package':<45} {'Before':<10} {'After':<10} {'Status'}")
    for c in changes:
