print(f"\n=== UNCHANGED ({len(unchanged)} entries) ===")
print(f"{'Project':<15} {'Framework':<8} {'Package':<45} {'Version'}")
for u in unchanged:
    print(f"{u[0]:<15} {u[1]:<8} {u[2]:<45} {u[3]}")
